#include <bits/stdc++.h>
using namespace std;
int main() {
	list<int> a;
	list<int>::iterator it;
	a.push_back(1);
	int n,r,c,e;
	std::ios::sync_with_stdio(0);
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>r;
		if(r==1){
			cin>>c;
			cin>>e;
			it = a.begin();
			while(*it!=c){
				it++;
			}it++;

			a.insert(it,e);
		}if(r==2){
			cin>>c;
			it = a.begin();
			while(*it!=c){
				it++;
			}
			it++;
			if(it==a.end())	{
				printf("0\n");
			}else{
				printf("%d\n",*it);
			}
		}if(r==3){
			cin>>c;
			it = a.begin();
			while(*it!=c){
				it++;
			}it++;
			a.erase(it);
		}
	}
}
